// src/app/admin/page.jsx
"use client";

import { useState, useEffect, useRef } from 'react';
import { FiLock, FiMail, FiLogIn, FiAlertCircle, FiEye, FiEyeOff } from 'react-icons/fi';
import { LuSparkles } from 'react-icons/lu';
import BlogManager from '@/components/BlogManager';
import gsap from 'gsap';

const AdminLogin = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });
  const [isClient, setIsClient] = useState(false);
  const [envLoaded, setEnvLoaded] = useState(false);

  // Refs for GSAP animations
  const loginCardRef = useRef(null);
  const errorRef = useRef(null);
  const spinnerRef = useRef(null);

  // Default credentials in case env variables are not loaded
  const DEFAULT_EMAIL = 'admin@riden.tech';
  const DEFAULT_PASSWORD = 'admin123';

  // Get credentials from environment variables with fallback to defaults
  const ADMIN_EMAIL = process.env.NEXT_PUBLIC_ADMIN_EMAIL || DEFAULT_EMAIL;
  const ADMIN_PASSWORD = process.env.NEXT_PUBLIC_ADMIN_PASSWORD || DEFAULT_PASSWORD;

  // Set isClient to true when component mounts (to avoid hydration issues)
  useEffect(() => {
    setIsClient(true);
    setEnvLoaded(true);
  }, []);

  // Check if already authenticated on mount
  useEffect(() => {
    if (isClient) {
      try {
        const auth = localStorage.getItem('admin-auth');
        setIsAuthenticated(auth === 'true');
      } catch (error) {
        console.error('Error accessing localStorage:', error);
        setIsAuthenticated(false);
      }
    }
  }, [isClient]);

  // Animate login card on mount
  useEffect(() => {
    if (loginCardRef.current && !isAuthenticated && isClient) {
      gsap.fromTo(loginCardRef.current,
        { opacity: 0, y: 20 },
        { opacity: 1, y: 0, duration: 0.5, ease: "power2.out" }
      );
    }
  }, [isAuthenticated, isClient]);

  // Animate error message when it appears
  useEffect(() => {
    if (error && errorRef.current) {
      gsap.fromTo(errorRef.current,
        { opacity: 0, y: -10 },
        { opacity: 1, y: 0, duration: 0.3, ease: "power2.out" }
      );
    }
  }, [error]);

  // Animate spinner when loading
  useEffect(() => {
    if (isLoading && spinnerRef.current) {
      gsap.to(spinnerRef.current, {
        rotation: 360,
        duration: 1,
        repeat: -1,
        ease: "linear"
      });
    }
  }, [isLoading]);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
    setError('');
  };

  const handleLogin = (e) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    // Simulate API call with timeout
    setTimeout(() => {
      // Check against credentials
      if (formData.email === ADMIN_EMAIL && formData.password === ADMIN_PASSWORD) {
        try {
          localStorage.setItem('admin-auth', 'true');
          setIsAuthenticated(true);
          setError('');
        } catch (error) {
          console.error('Error setting localStorage:', error);
          setError('Failed to save authentication state');
        }
      } else {
        setError(`Invalid email or password. Try ${ADMIN_EMAIL} / ${ADMIN_PASSWORD}`);
      }
      setIsLoading(false);
    }, 800);
  };

  const handleLogout = () => {
    try {
      localStorage.removeItem('admin-auth');
    } catch (error) {
      console.error('Error removing from localStorage:', error);
    }
    setIsAuthenticated(false);
    setFormData({ email: '', password: '' });
  };

  // Don't render anything until client-side to avoid hydration mismatch
  if (!isClient || !envLoaded) {
    return null;
  }

  if (isAuthenticated) {
    return (
      <div className="min-h-screen bg-white">
        {/* Admin Header - Black/White theme */}
        <div className="bg-gradient-to-r from-gray-900 to-black text-white border-b border-gray-800">
          <div className="max-w-7xl mx-auto px-4 py-4">
            <div className="flex justify-between items-center">
              <div className="flex items-center space-x-2">
                <LuSparkles className="text-2xl text-white" />
                <span className="font-['Marcellus'] text-xl">Admin Dashboard</span>
              </div>
              <button
                onClick={handleLogout}
                className="px-4 py-2 bg-white/10 hover:bg-white/20 rounded-lg transition-colors text-sm flex items-center border border-gray-700"
              >
                <FiLock className="mr-2" />
                Logout
              </button>
            </div>
          </div>
        </div>

        {/* Blog Manager */}
        <BlogManager />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-white flex items-center justify-center p-4">
      {/* Background Pattern - Black dots */}
      <div 
        className="absolute inset-0 opacity-10"
        style={{
          backgroundImage: `radial-gradient(circle at 1px 1px, #000000 1px, transparent 0)`,
          backgroundSize: '30px 30px'
        }}
      />

      {/* Login Card */}
      <div
        ref={loginCardRef}
        className="relative bg-white rounded-2xl shadow-2xl max-w-md w-full p-8 border border-gray-200"
      >
        {/* Decorative Elements - Black/White */}
        <div className="absolute -top-3 -right-3 w-20 h-20 bg-gray-900/5 rounded-full blur-2xl" />
        <div className="absolute -bottom-3 -left-3 w-20 h-20 bg-gray-800/5 rounded-full blur-2xl" />

        {/* Logo/Brand */}
        <div className="text-center mb-8">
          <div className="inline-block p-3 bg-gradient-to-br from-gray-900/5 to-gray-600/5 rounded-2xl mb-4 border border-gray-100">
            <LuSparkles className="text-3xl text-gray-900" />
          </div>
          <h1 className="font-['Marcellus'] text-3xl text-gray-900 mb-2">
            Admin <span className="text-gray-500">Access</span>
          </h1>
          <p className="text-gray-500 text-sm">
            Enter your credentials to manage blog posts
          </p>
          {/* Show demo credentials hint */}
          <p className="text-xs text-gray-400 mt-2">
            Demo: {ADMIN_EMAIL} / {ADMIN_PASSWORD}
          </p>
        </div>

        {/* Error Alert */}
        {error && (
          <div
            ref={errorRef}
            className="mb-6 p-3 bg-gray-100 border border-gray-200 rounded-lg flex items-center text-gray-800 text-sm"
          >
            <FiAlertCircle className="mr-2 flex-shrink-0 text-gray-700" />
            {error}
          </div>
        )}

        {/* Login Form */}
        <form onSubmit={handleLogin} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-600 mb-2">
              Email Address
            </label>
            <div className="relative">
              <FiMail className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
              <input
                type="email"
                name="email"
                value={formData.email}
                onChange={handleChange}
                required
                placeholder={ADMIN_EMAIL}
                className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-gray-900 focus:border-gray-900 transition-colors bg-white text-gray-900 placeholder-gray-400"
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-600 mb-2">
              Password
            </label>
            <div className="relative">
              <FiLock className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
              <input
                type={showPassword ? 'text' : 'password'}
                name="password"
                value={formData.password}
                onChange={handleChange}
                required
                placeholder="â€¢â€¢â€¢â€¢â€¢â€¢â€¢â€¢"
                className="w-full pl-10 pr-10 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-gray-900 focus:border-gray-900 transition-colors bg-white text-gray-900 placeholder-gray-400"
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-gray-600"
              >
                {showPassword ? <FiEyeOff size={18} /> : <FiEye size={18} />}
              </button>
            </div>
          </div>

          {/* Remember me & Forgot password */}
          <div className="flex items-center justify-between">
            <label className="flex items-center">
              <input type="checkbox" className="w-4 h-4 text-gray-900 border-gray-300 rounded focus:ring-gray-900" />
              <span className="ml-2 text-sm text-gray-600">Remember me</span>
            </label>
            <button
              type="button"
              onClick={() => alert(`Demo credentials: ${ADMIN_EMAIL} / ${ADMIN_PASSWORD}`)}
              className="text-sm text-gray-600 hover:text-gray-900 transition-colors"
            >
              Forgot password?
            </button>
          </div>

          {/* Login Button */}
          <button
            type="submit"
            disabled={isLoading}
            className="w-full py-3 bg-gray-900 text-white rounded-lg hover:bg-gray-800 transition-all duration-300 font-medium flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed border border-gray-800"
          >
            {isLoading ? (
              <div
                ref={spinnerRef}
                className="w-5 h-5 border-2 border-white border-t-transparent rounded-full"
              />
            ) : (
              <>
                <FiLogIn className="mr-2" />
                Sign In
              </>
            )}
          </button>
        </form>

        {/* Demo Note */}
        <div className="mt-6 p-3 bg-gray-50 border border-gray-200 rounded-lg">
          <p className="text-xs text-gray-500 text-center">
            <span className="font-medium text-gray-700">Demo Credentials:</span><br />
            Email: {ADMIN_EMAIL}<br />
            Password: {ADMIN_PASSWORD}
          </p>
        </div>

        {/* Footer */}
        <p className="text-center text-xs text-gray-400 mt-6">
          Â© {new Date().getFullYear()} RidenTech. All rights reserved.
        </p>
      </div>
    </div>
  );
};

export default AdminLogin;

// app/contact/page.jsx
"use client";

import React, { useEffect, useRef, useCallback, forwardRef, useState } from "react";
import Link from "next/link";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import HeroSection from "@/components/HeroSection";
import { 
  FiMail, FiPhone, FiMapPin, FiClock, FiSend, 
  FiGithub, FiTwitter, FiLinkedin, FiInstagram,
  FiCheckCircle
} from "react-icons/fi";
import { BsCalendarCheck } from "react-icons/bs";

gsap.registerPlugin(ScrollTrigger);

export default function ContactPage() {
  const sectionRef = useRef(null);
  const formRef = useRef(null);
  const titleRef = useRef(null);
  const subtitleRef = useRef(null);
  const cardsContainerRef = useRef(null);
  const cardRefs = useRef([]);
  const socialRefs = useRef([]);
  const footerRef = useRef(null);
  const [formStatus, setFormStatus] = useState({ submitted: false, success: false, message: '' });
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    message: ''
  });

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // Simulate form submission
    setFormStatus({ submitted: true, success: true, message: 'Thank you! We\'ll get back to you soon.' });
    
    // Reset form after 3 seconds
    setTimeout(() => {
      setFormStatus({ submitted: false, success: false, message: '' });
      setFormData({
        name: '',
        email: '',
        message: ''
      });
    }, 3000);
  };

  useEffect(() => {
    const ctx = gsap.context(() => {
      // Title and subtitle animations
      const headerTl = gsap.timeline({
        scrollTrigger: {
          trigger: sectionRef.current,
          start: "top 80%",
          end: "bottom 20%",
          toggleActions: "play none none reverse"
        }
      });

      headerTl.fromTo([titleRef.current, subtitleRef.current],
        { y: 40, opacity: 0 },
        { y: 0, opacity: 1, duration: 0.8, stagger: 0.2, ease: "power3.out" }
      );

      // Form animation
      gsap.fromTo(formRef.current,
        { y: 50, opacity: 0, scale: 0.98 },
        { 
          y: 0, 
          opacity: 1, 
          scale: 1,
          duration: 1, 
          ease: "power3.out",
          scrollTrigger: {
            trigger: formRef.current,
            start: "top 80%",
            toggleActions: "play none none reverse"
          }
        }
      );

      // Contact cards animations
      gsap.fromTo(cardRefs.current,
        { y: 30, opacity: 0, scale: 0.95 },
        { 
          y: 0, 
          opacity: 1, 
          scale: 1,
          duration: 0.6, 
          stagger: 0.15,
          ease: "back.out(1.4)",
          scrollTrigger: {
            trigger: cardsContainerRef.current,
            start: "top 80%",
            toggleActions: "play none none reverse"
          }
        }
      );

      // Social icons animation
      gsap.fromTo(socialRefs.current,
        { scale: 0, opacity: 0 },
        { 
          scale: 1, 
          opacity: 1,
          duration: 0.5, 
          stagger: 0.1,
          ease: "back.out(1.7)",
          scrollTrigger: {
            trigger: cardsContainerRef.current,
            start: "top 80%",
            toggleActions: "play none none reverse"
          }
        }
      );

      // Footer animation
      gsap.fromTo(footerRef.current,
        { y: 50, opacity: 0 },
        { 
          y: 0, 
          opacity: 1, 
          duration: 1, 
          ease: "power3.out",
          scrollTrigger: {
            trigger: footerRef.current,
            start: "top 90%",
            toggleActions: "play none none reverse"
          }
        }
      );

    }, [sectionRef, formRef, cardsContainerRef, footerRef]);

    return () => ctx.revert();
  }, []);

  return (
    <div className="min-h-screen bg-white">
      {/* Hero Section */}
      <HeroSection
        title="CONTACT US"
        subtitle="Building a legacy of innovation and trust"
        imageSrc="https://images.unsplash.com/photo-1551434678-e076c223a692?q=80&w=2070&auto=format&fit=crop"
        overlayColor="bg-white"
      />

      {/* Contact Form Section */}
      <section id="contact-form" ref={sectionRef} className="py-16 scroll-mt-24">
        <div className="max-w-7xl mx-auto px-4">
          <div ref={titleRef} className="text-center mb-12">
            <h2 className="font-['Marcellus'] text-3xl md:text-4xl text-gray-900 mb-4">
              Send Us a{" "}
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-gray-900 to-gray-600">
                Message
              </span>
            </h2>

            <p ref={subtitleRef} className="font-['Manrope'] text-gray-600 max-w-2xl mx-auto">
              Fill out the form below and we'll get back to you within 24 hours.
            </p>
          </div>

          <div
            ref={formRef}
            className="bg-white rounded-2xl shadow-xl border border-gray-200 overflow-hidden max-w-2xl mx-auto"
          >
            <div className="p-6 bg-gradient-to-r from-gray-900 to-gray-700">
              <div className="flex items-center gap-3">
                <FiSend className="w-6 h-6 text-white" />
                <h3 className="font-['Marcellus'] text-xl text-white">
                  Get in Touch
                </h3>
              </div>
            </div>

            {/* Contact Form */}
            <div className="p-8 bg-gray-50">
              {formStatus.submitted ? (
                <div className="text-center py-12">
                  <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
                    <FiCheckCircle className="w-10 h-10 text-green-600" />
                  </div>
                  <h3 className="font-['Manrope'] font-semibold text-xl text-gray-900 mb-2">Message Sent!</h3>
                  <p className="font-['Instrument_Sans'] text-gray-600">{formStatus.message}</p>
                </div>
              ) : (
                <form onSubmit={handleSubmit} className="space-y-6">
                  <div>
                    <label className="block font-['Manrope'] text-sm font-medium text-gray-700 mb-2">
                      Your Name *
                    </label>
                    <input
                      type="text"
                      name="name"
                      value={formData.name}
                      onChange={handleChange}
                      required
                      className="w-full px-4 py-3 border border-gray-200 rounded-lg focus:ring-2 focus:ring-gray-900 focus:border-gray-900 transition-colors bg-white text-gray-900"
                      placeholder="John Doe"
                    />
                  </div>

                  <div>
                    <label className="block font-['Manrope'] text-sm font-medium text-gray-700 mb-2">
                      Email Address *
                    </label>
                    <input
                      type="email"
                      name="email"
                      value={formData.email}
                      onChange={handleChange}
                      required
                      className="w-full px-4 py-3 border border-gray-200 rounded-lg focus:ring-2 focus:ring-gray-900 focus:border-gray-900 transition-colors bg-white text-gray-900"
                      placeholder="john@example.com"
                    />
                  </div>

                  <div>
                    <label className="block font-['Manrope'] text-sm font-medium text-gray-700 mb-2">
                      Your Message *
                    </label>
                    <textarea
                      name="message"
                      value={formData.message}
                      onChange={handleChange}
                      required
                      rows="5"
                      className="w-full px-4 py-3 border border-gray-200 rounded-lg focus:ring-2 focus:ring-gray-900 focus:border-gray-900 transition-colors bg-white text-gray-900 resize-none"
                      placeholder="Tell us about your project..."
                    ></textarea>
                  </div>

                  <button
                    type="submit"
                    className="w-full bg-gray-900 text-white py-4 rounded-lg font-['Manrope'] font-medium hover:bg-gray-800 transition-all duration-300 flex items-center justify-center gap-2 group"
                  >
                    <span>Send Message</span>
                    <FiSend className="w-4 h-4 transition-transform duration-300 group-hover:translate-x-1" />
                  </button>

                  <p className="text-xs text-gray-500 text-center mt-4">
                    By submitting this form, you agree to our privacy policy and terms of service.
                  </p>
                </form>
              )}
            </div>
          </div>
        </div>
      </section>

      {/* Contact Cards & Social Links */}
      <section className="py-20 bg-white">
        <div ref={cardsContainerRef} className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="text-center mb-12">
            <h2 className="font-['Marcellus'] text-3xl md:text-4xl text-gray-900 mb-4">
              Other Ways to{" "}
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-gray-900 to-gray-600">
                Connect
              </span>
            </h2>
            <p className="font-['Manrope'] text-gray-600 max-w-2xl mx-auto">
              Choose the channel that works best for you
            </p>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 mb-12">
            <ContactCard
              ref={el => cardRefs.current[0] = el}
              icon={<FiMail />}
              title="Email"
              text="hello@riden.tech"
              link="mailto:hello@riden.tech"
            />

            <ContactCard
              ref={el => cardRefs.current[1] = el}
              icon={<FiPhone />}
              title="Call"
              text="+1 (555) 123-4567"
              link="tel:+15551234567"
            />

            <ContactCard
              ref={el => cardRefs.current[2] = el}
              icon={<FiMapPin />}
              title="Visit"
              text="San Francisco, CA"
            />
          </div>

          {/* Social Links */}
          <div className="flex flex-col items-center">
            <h3 className="font-['Marcellus'] text-xl text-gray-900 mb-6">Follow Us</h3>
            <div className="flex gap-4">
              {[
                { icon: <FiGithub />, href: "#", label: "GitHub" },
                { icon: <FiTwitter />, href: "#", label: "Twitter" },
                { icon: <FiLinkedin />, href: "#", label: "LinkedIn" },
                { icon: <FiInstagram />, href: "#", label: "Instagram" }
              ].map((social, index) => (
                <a
                  key={index}
                  ref={el => socialRefs.current[index] = el}
                  href={social.href}
                  className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center text-gray-700 hover:bg-gray-900 hover:text-white transition-all duration-300 hover:scale-110"
                  aria-label={social.label}
                >
                  {social.icon}
                </a>
              ))}
            </div>
          </div>
        </div>
      </section>

      {/* Simple Footer */}
      <footer ref={footerRef} className="bg-black text-white py-12">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            {/* Logo & Description */}
            <div>
              <h3 className="font-['Marcellus'] text-2xl mb-4">Riden<span className="text-gray-400">Tech</span></h3>
              <p className="font-['Manrope'] text-sm text-gray-400">
                Building innovative digital solutions for forward-thinking businesses.
              </p>
            </div>

            {/* Quick Links */}
            <div>
              <h4 className="font-['Marcellus'] text-lg mb-4">Quick Links</h4>
              <ul className="space-y-2">
                <li><Link href="/about" className="font-['Manrope'] text-sm text-gray-400 hover:text-white transition-colors">About</Link></li>
                <li><Link href="/services" className="font-['Manrope'] text-sm text-gray-400 hover:text-white transition-colors">Services</Link></li>
                <li><Link href="/work" className="font-['Manrope'] text-sm text-gray-400 hover:text-white transition-colors">Work</Link></li>
                <li><Link href="/blog" className="font-['Manrope'] text-sm text-gray-400 hover:text-white transition-colors">Blog</Link></li>
              </ul>
            </div>

            {/* Contact Info */}
            <div>
              <h4 className="font-['Marcellus'] text-lg mb-4">Contact</h4>
              <ul className="space-y-2">
                <li className="font-['Manrope'] text-sm text-gray-400 flex items-center gap-2">
                  <FiMail className="w-4 h-4" /> hello@riden.tech
                </li>
                <li className="font-['Manrope'] text-sm text-gray-400 flex items-center gap-2">
                  <FiPhone className="w-4 h-4" /> +1 (555) 123-4567
                </li>
                <li className="font-['Manrope'] text-sm text-gray-400 flex items-center gap-2">
                  <FiMapPin className="w-4 h-4" /> San Francisco, CA
                </li>
              </ul>
            </div>
          </div>

