      } else if (window.innerWidth < 1024) {
        setClipPath("path('M 15,30 L 150,30 A 15,15 0,0,0 165,15 L 165,15 A 15,15 0,0,1 180,0 L 390,0 A 15,15 0,0,1 405,15 L 405,352 A 15,15 0,0,1 390,367 L 15,367 A 15,15 0,0,1 0,352 L 0,45 A 15,15 0,0,1 15,30 Z')");
      } else {
        setClipPath("path('M 20,40 L 200,40 A 20,20 0,0,0 220,20 L 220,20 A 20,20 0,0,1 240,0 L 520,0 A 20,20 0,0,1 540,20 L 540,470 A 20,20 0,0,1 520,490 L 20,490 A 20,20 0,0,1 0,470 L 0,60 A 20,20 0,0,1 20,40 Z')");
      }
    };

    updateClipPath();
    window.addEventListener('resize', updateClipPath);

    // Set initial states
    gsap.set([badgeRef.current, titleRef.current, subtitleRef.current, headingRef.current,
    descriptionRef.current, ...featuresRef.current.filter(el => el),
    borderLineRef.current, ctaRef.current, imageRef.current], {
      opacity: 0,
      y: 30
    });

    const ctx = gsap.context(() => {
      // Create a master timeline with delays
      const masterTl = gsap.timeline({
        scrollTrigger: {
          trigger: sectionRef.current,
          start: "top 70%",
          end: "bottom 20%",
          toggleActions: "play none none reverse",
          once: true // Only animate once
        }
      });

      // Badge animation with delay
      masterTl.to(badgeRef.current, {
        y: 0,
        opacity: 1,
        duration: 0.8,
        ease: "power3.out"
      }, 0.2); // 0.2s delay

      // Title and subtitle with staggered delay
      masterTl.to([titleRef.current, subtitleRef.current], {
        y: 0,
        opacity: 1,
        duration: 0.9,
        stagger: 0.2,
        ease: "power4.out"
      }, 0.4); // 0.4s delay

      // Heading with delay
      masterTl.to(headingRef.current, {
        y: 0,
        opacity: 1,
        duration: 0.8,
        ease: "power3.out"
      }, 0.6); // 0.6s delay

      // Image animation with delay
      masterTl.fromTo(imageRef.current,
        {
          opacity: 0,
          scale: 0.9,
          rotation: 2
        },
        {
          opacity: 1,
          scale: 1,
          rotation: 0,
          duration: 1.4,
          ease: "power3.out"
        },
        0.8 // 0.8s delay
      );

      // Description with delay
      masterTl.to(descriptionRef.current, {
        y: 0,
        opacity: 1,
        duration: 0.8,
        ease: "power3.out"
      }, 1.0); // 1.0s delay

      // Features with staggered delay
      const validFeatures = featuresRef.current.filter(el => el);
      if (validFeatures.length > 0) {
        validFeatures.forEach((feature, index) => {
          masterTl.to(feature, {
            x: 0,
            opacity: 1,
            duration: 0.6,
            ease: "power3.out"
          }, 1.2 + (index * 0.15)); // Staggered starting at 1.2s
        });
      }

      // Border line with delay
      masterTl.to(borderLineRef.current, {
        scaleX: 1,
        opacity: 1,
        duration: 1,
        ease: "power3.out"
      }, 1.8); // 1.8s delay

      // CTA with delay
      masterTl.to(ctaRef.current, {
        y: 0,
        opacity: 1,
        duration: 0.7,
        ease: "back.out(1.2)"
      }, 2.0); // 2.0s delay



      // Parallax effect for background elements (continuous)
      gsap.to('.mission-bg-1', {
        y: 30,
        scrollTrigger: {
          trigger: sectionRef.current,
          start: "top bottom",
          end: "bottom top",
          scrub: 1
        }
      });

      gsap.to('.mission-bg-2', {
        y: -30,
        scrollTrigger: {
          trigger: sectionRef.current,
          start: "top bottom",
          end: "bottom top",
          scrub: 1
        }
      });
    });

    return () => {
      ctx.revert();
      ScrollTrigger.getAll().forEach(t => {
        if (t.trigger === sectionRef.current) t.kill(true);
      });
      window.removeEventListener('resize', updateClipPath);
    };
  }, [mounted]);

  // Hover handlers for feature items
  const handleFeatureEnter = (e) => {
    gsap.to(e.currentTarget, {
      x: 5,
      duration: 0.3,
      ease: "power2.out"
    });
    gsap.to(e.currentTarget.querySelector('.feature-icon'), {
      scale: 1.1,
      backgroundColor: '#1f2937',
      duration: 0.3,
      ease: "power2.out"
    });
  };

  const handleFeatureLeave = (e) => {
    gsap.to(e.currentTarget, {
      x: 0,
      duration: 0.3,
      ease: "power2.out"
    });
    gsap.to(e.currentTarget.querySelector('.feature-icon'), {
      scale: 1,
      backgroundColor: '#111827',
      duration: 0.3,
      ease: "power2.out"
    });
  };

  if (!mounted) return <section ref={sectionRef} className="relative py-24 bg-white overflow-hidden" />;

  return (
    <section ref={sectionRef} className="relative py-24 bg-white overflow-hidden">
      {/* Background decorative elements with parallax */}
      <div className="mission-bg-1 absolute top-40 right-0 w-96 h-96 bg-gray-100 rounded-full filter blur-3xl opacity-20"></div>
      <div className="mission-bg-2 absolute bottom-20 left-20 w-72 h-72 bg-gray-100 rounded-full filter blur-3xl opacity-20"></div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
        <div className="text-center mb-12">
          {/* Floating Badge */}
          <div
            ref={badgeRef}
            className="inline-flex items-center bg-gradient-to-r from-gray-900 to-gray-700 text-white rounded-full px-5 py-2.5 mb-6 shadow-lg opacity-0"
          >
            <Zap className="w-4 h-4 mr-2" />
            <span className="text-sm font-manrope font-medium tracking-wide">OUR MISSION</span>
          </div>

          {/* Titles with animation */}
          <h2 ref={titleRef} className="font-marcellus text-5xl md:text-6xl text-gray-900 mb-4 opacity-0">
            Your Success,
          </h2>
          <h2 ref={subtitleRef} className="font-marcellus text-5xl md:text-6xl text-gray-900 mb-6 opacity-0">
            <span className="relative">
              Our Priority.
            </span>
          </h2>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 items-center">
          <div className="relative order-2 lg:order-1">
            <div className="relative h-[400px] sm:h-[500px] md:h-[550px] lg:h-[600px] w-full max-w-[320px] sm:max-w-[450px] md:max-w-[550px] lg:max-w-[600px] mx-auto">
              <div
                ref={imageRef}
                className="absolute inset-0 w-full h-full shadow-2xl opacity-0"
                style={{
                  clipPath: clipPath,
                }}
              >
                <div
                  className="w-full h-full bg-cover bg-center"
                  style={{
                    backgroundImage: "url('https://images.unsplash.com/photo-1522071820081-009f0129c71c?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=2070&q=80')"
                  }}
                ></div>
              </div>
            </div>
          </div>

          {/* Right Side - Content */}
          <div className="order-1 lg:order-2 space-y-6">
            {/* Heading with animation */}
            <p ref={headingRef} className="font-instrument text-xl text-gray-600 leading-relaxed opacity-0">
              We&apos;re dedicated to helping you achieve your goals with a simple, user-friendly experience.
              We believe our commitment to your success sets us apart.
            </p>

            {/* Description Text */}
            <div ref={descriptionRef} className="space-y-4 opacity-0">
              <p className="font-instrument text-lg text-gray-600 leading-relaxed">
                Our approach combines strategic thinking with technical excellence to deliver solutions
                that not only meet but exceed expectations.
              </p>
            </div>

            {/* Features List */}
            <div className="space-y-4 pt-2">
              {features.map((feature, index) => (
                <div
                  key={index}
                  ref={el => featuresRef.current[index] = el}
                  className="flex items-start space-x-3 cursor-pointer group opacity-0"
                  style={{ transform: 'translateX(30px)' }}
                  onMouseEnter={handleFeatureEnter}
                  onMouseLeave={handleFeatureLeave}
                >
                  <div className="feature-icon flex-shrink-0 w-8 h-8 bg-gray-900 text-white rounded-lg flex items-center justify-center transition-all duration-300">
                    {feature.icon}
                  </div>
                  <div className="flex-1">
                    <h3 className="font-marcellus text-lg text-gray-900 mb-1">
                      {feature.title}
                    </h3>
                    <p className="font-instrument text-sm text-gray-600 leading-relaxed">
                      {feature.description}
                    </p>
                  </div>
                </div>
              ))}
            </div>

            {/* Border Line with animation */}
            <div ref={borderLineRef} className="w-full h-px bg-gray-200 origin-left my-6 opacity-0 scale-x-0"></div>

            {/* CTA with animation */}
            <div ref={ctaRef} className="flex flex-wrap gap-4 opacity-0">
              <Link
                href="/contact"
                className="group inline-flex items-center space-x-2 bg-gray-900 text-white px-8 py-4 rounded-lg text-sm font-medium hover:bg-gray-800 transition-all duration-300 hover:shadow-lg font-manrope"
              >
                <span>Start Projects</span>
                <ArrowRight className="w-4 h-4 transition-transform duration-300 group-hover:translate-x-1" />
              </Link>

              <Link
                href="/about"
                className="group inline-flex items-center space-x-2 border-2 border-gray-900 text-gray-900 px-8 py-4 rounded-lg text-sm font-medium hover:bg-gray-900 hover:text-white transition-all duration-300 hover:shadow-lg font-manrope"
              >
                <span>Learn More</span>
              </Link>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default AboutUs;

"use client";

import { useEffect, useRef, useState } from "react";
import Image from "next/image";
import Link from "next/link";
import { ArrowRight, ArrowUpRight, MessageCircle, Calendar, Clock, Sparkles, ChevronLeft, ChevronRight, Zap } from "lucide-react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { Draggable } from "gsap/Draggable";
import { blogPosts } from "@/app/data/blogData";

gsap.registerPlugin(ScrollTrigger, Draggable);

export default function Blog() {
  const sectionRef = useRef(null);
  const trackRef = useRef(null);
  const stickyRef = useRef(null);
  const titleRef = useRef(null);
  const textRef = useRef(null);
  const buttonRef = useRef(null);
  const mobileButtonRef = useRef(null);
  const badgeRef = useRef(null); // Added badge ref
  const statsRef = useRef([]);
  const scrollContainerRef = useRef(null);
  const prevButtonRef = useRef(null);
  const nextButtonRef = useRef(null);

  const [scrollLength, setScrollLength] = useState(0);
  const [currentPosition, setCurrentPosition] = useState(0);
  const [isMobile, setIsMobile] = useState(false);
  const [isTablet, setIsTablet] = useState(false);
  const recentPosts = [...blogPosts].sort((a, b) => b.id - a.id).slice(0, 6);

  const [mounted, setMounted] = useState(false);
  const pinContainerRef = useRef(null);

  useEffect(() => {
    setMounted(true);
  }, []);

  // Check screen size
  useEffect(() => {
    if (!mounted) return;
    const checkScreenSize = () => {
      setIsMobile(window.innerWidth < 768);
      setIsTablet(window.innerWidth >= 768 && window.innerWidth < 1024);
    };

    checkScreenSize();
    window.addEventListener("resize", checkScreenSize);
    return () => window.removeEventListener("resize", checkScreenSize);
  }, [mounted]);

  // Calculate scroll width for all devices
  useEffect(() => {
    if (!mounted) return;
    const updateScrollLength = () => {
      if (!trackRef.current || !sectionRef.current) return;

      const trackWidth = trackRef.current.scrollWidth;
      const containerWidth = isMobile || isTablet
        ? window.innerWidth - 48
        : stickyRef.current
          ? sectionRef.current.offsetWidth - stickyRef.current.offsetWidth
          : sectionRef.current.offsetWidth;

      setScrollLength(trackWidth - containerWidth + (isMobile ? 40 : 60));
      ScrollTrigger.refresh();
    };

    updateScrollLength();
    window.addEventListener("resize", updateScrollLength);
    return () => window.removeEventListener("resize", updateScrollLength);
  }, [isMobile, isTablet, mounted]);

  // Handle side button navigation
  const scrollTo = (direction) => {
    if (!trackRef.current || !scrollContainerRef.current) return;

    const cardWidth = isMobile ? 280 : 300;
    const gap = 16; // 4 * 4 = 16px
    const scrollAmount = cardWidth + gap;

    let newPosition;
    if (direction === 'prev') {
      newPosition = Math.min(currentPosition + scrollAmount, 0);
    } else {
      newPosition = Math.max(currentPosition - scrollAmount, -scrollLength);
    }

    setCurrentPosition(newPosition);

    gsap.to(trackRef.current, {
      x: newPosition,
      duration: 0.5,
      ease: "power2.out"
    });
  };

  // GSAP animations
  useEffect(() => {
    if (!mounted) return;
    const ctx = gsap.context(() => {
      if (!sectionRef.current || !trackRef.current) return;

      // Set initial opacity to 1 for buttons to ensure they're visible
      if (buttonRef.current) {
        gsap.set(buttonRef.current, { opacity: 1, y: 0 });
      }
      if (mobileButtonRef.current) {
        gsap.set(mobileButtonRef.current, { opacity: 1, y: 0 });
      }
      if (badgeRef.current) {
        gsap.set(badgeRef.current, { opacity: 1, y: 0 });
      }

      // Title and content animations
      const elementsToAnimate = [badgeRef.current, titleRef.current, textRef.current];

      gsap.from(elementsToAnimate, {
        y: isMobile ? 20 : 60,
        opacity: 0,
        duration: isMobile ? 0.6 : 1,
        stagger: isMobile ? 0.1 : 0.15,
        ease: "power2.out",
        scrollTrigger: {
          trigger: sectionRef.current,
          start: "top 80%",
          toggleActions: "play none none none"
        }
      });

      // Animate stats separately if they exist
      if (statsRef.current.length > 0) {
        gsap.from(statsRef.current, {
          y: isMobile ? 20 : 60,
          opacity: 0,
          duration: isMobile ? 0.6 : 1,
          stagger: 0.1,
          ease: "power2.out",
          scrollTrigger: {
            trigger: sectionRef.current,
            start: "top 80%",
            toggleActions: "play none none none"
          }
        });
      }

      // Desktop horizontal scroll animation
      if (!isMobile && !isTablet && scrollLength > 0) {
        ScrollTrigger.create({
          trigger: sectionRef.current,
          start: "top top",
          end: () => `+=${scrollLength + window.innerHeight}`, // Use window height for better completion feel
          scrub: 1,
          pin: true, // Pin the whole section
          pinSpacing: true,
          anticipatePin: 1,
          invalidateOnRefresh: true,
          animation: gsap.to(trackRef.current, {
            x: () => -scrollLength,
            ease: "none",
          })
        });
      }

      // Card entrance animations
      const cards = trackRef.current.children;
      Array.from(cards).forEach((card, index) => {
        gsap.fromTo(card,
          {
            opacity: 0,
            scale: isMobile ? 0.95 : 0.9,
            x: isMobile ? 30 : 100
          },
          {
            opacity: 1,
            scale: 1,
            x: 0,
            duration: isMobile ? 0.5 : 0.8,
            delay: index * (isMobile ? 0.08 : 0.15),
            ease: "power2.out",
            scrollTrigger: {
              trigger: sectionRef.current,
              start: "top 70%",
              toggleActions: "play none none none"
            }
          }
        );
      });

      // Initialize draggable for mobile/tablet
      if ((isMobile || isTablet) && trackRef.current && scrollContainerRef.current) {
        Draggable.create(trackRef.current, {
          type: "x",
          edgeResistance: 0.65,
          bounds: {
            minX: -scrollLength,
            maxX: 0
          },
          inertia: true,
          onDrag: function () {
            setCurrentPosition(this.x);
          }
        });
      }

    }, sectionRef);

    return () => {
      ctx.revert();
      ScrollTrigger.getAll().forEach(t => {
        if (t.trigger === sectionRef.current || t.pin === pinContainerRef.current) t.kill(true);
      });
    };
  }, [scrollLength, isMobile, isTablet, mounted]);

  if (!mounted) return (
    <section
      ref={sectionRef}
      className={`w-full ${isMobile || isTablet ? 'py-16' : 'h-[120vh]'} bg-gradient-to-br from-white to-gray-50 relative overflow-hidden`}
    />
  );

  return (
    <section
      ref={sectionRef}
      className={`w-full ${isMobile || isTablet ? 'py-16' : 'min-h-screen'} bg-gradient-to-br from-white to-gray-50 relative overflow-hidden`}
    >
      <div ref={pinContainerRef} className="w-full h-full">
        {/* Background decorative elements */}
        <div className="absolute inset-0 pointer-events-none">
          <div className="absolute top-40 right-0 w-96 h-96 bg-gray-200 rounded-full filter blur-3xl opacity-20"></div>
          <div className="absolute bottom-40 left-1/3 w-72 h-72 bg-gray-200 rounded-full filter blur-3xl opacity-20"></div>
        </div>

        {/* Desktop Layout */}
        {!isMobile && !isTablet && (
          <div className="flex items-center h-full relative z-10">
            {/* LEFT CONTENT */}
            <div
              ref={stickyRef}
              className="w-[40vw] px-16 sticky left-0 top-0 h-full flex flex-col justify-center bg-white z-20 "
            >
              {/* Floating Badge - Exact match */}
              <div
                ref={badgeRef}
                className="inline-flex items-center bg-gradient-to-r from-gray-900 to-gray-700 text-white rounded-full px-5 py-2.5 mb-6 shadow-lg w-fit"
              >
                <Zap className="w-4 h-4 mr-2" />
                <span className="text-sm font-manrope font-medium tracking-wide">LATEST INSIGHTS</span>
              </div>

              {/* Title */}
              <h2
                ref={titleRef}
                className="font-marcellus text-7xl text-gray-900 mb-6 leading-[0.9]"
              >
                Blogs &<br />
                <span className="text-gray-700 italic">Insights</span>
              </h2>

              {/* Description */}
              <p
                ref={textRef}
                className="font-instrument text-gray-600 max-w-md mb-10 leading-relaxed text-lg"
              >
                Discover strategies, ideas, and insights from our team to help your
                brand grow, innovate, and succeed in the digital world.
              </p>

              {/* CTA Button - Desktop */}
              <Link
                ref={buttonRef}
                href="/blogs"
                className="group relative inline-flex items-center gap-3 bg-gray-900 text-white px-8 py-4 rounded-xl text-sm font-medium overflow-hidden transition-all duration-300 hover:shadow-xl hover:shadow-gray-900/20 font-manrope w-fit"
                style={{ opacity: 1 }}
              >
                <span className="relative z-10">View All Articles</span>
                <ArrowUpRight className="relative z-10 w-4 h-4 transition-all duration-300 group-hover:translate-x-1 group-hover:-translate-y-1" />
                <div className="absolute inset-0 bg-gradient-to-r from-gray-800 to-gray-900 transform scale-x-0 group-hover:scale-x-100 transition-transform duration-300 origin-left"></div>
              </Link>
            </div>

            {/* BLOG CARDS - Horizontal Scroll */}
            <div
              ref={trackRef}
              className="flex gap-8 ml-10 pr-40 items-center"
              style={{ overflow: "visible" }}
            >
              {recentPosts.map((post, index) => (
                <Link
                  href={`/blog/${post.slug}`}
                  key={post.id}
                  className="group w-[380px] bg-white rounded-2xl border border-gray-200 shadow-lg hover:shadow-2xl transition-all duration-500 overflow-hidden hover:-translate-y-2 hover:border-gray-400"
                >
                  {/* IMAGE */}
                  <div className="relative h-56 w-full overflow-hidden">
                    <Image
                      src={post.image}
                      alt={post.title}
                      fill
                      className="object-cover transition-transform duration-700 group-hover:scale-110"
                    />

                    {/* Gradient Overlay */}
                    <div className="absolute inset-0 bg-gradient-to-t from-black/40 via-transparent to-transparent opacity-60"></div>

                    {/* Category Badge */}
                    <div className="absolute top-4 right-4 z-10">
                      <span className="px-3 py-1.5 bg-white/95 backdrop-blur-sm text-gray-900 text-xs font-manrope font-semibold uppercase tracking-wider rounded-full shadow-lg border border-gray-200">
                        {post.category}
                      </span>
                    </div>


                  </div>

                  {/* CONTENT */}
                  <div className="p-6">
                    {/* META */}
                    <div className="flex items-center gap-4 mb-4 text-gray-500 text-sm font-manrope">
                      <div className="flex items-center gap-1.5">
                        <Calendar className="w-4 h-4" />
                        <span>{post.day} {post.month}, {post.year}</span>
                      </div>
                    </div>

                    {/* TITLE */}
                    <h3 className="font-marcellus text-xl font-bold text-gray-900 mb-3 line-clamp-2 group-hover:text-gray-700 transition-colors duration-300">
                      {post.title}
                    </h3>

                    {/* EXCERPT */}
                    <p className="font-instrument text-gray-600 text-sm mb-5 line-clamp-2 leading-relaxed">
                      {post.excerpt}
                    </p>

                    {/* AUTHOR & READ MORE */}
                    <div className="flex items-center justify-between pt-4 border-t border-gray-100">

                      <div className="flex items-center gap-1 text-gray-600 group-hover:text-gray-900 transition-colors duration-300">
                        <span className="font-manrope text-sm font-medium">Read</span>
                        <ArrowRight className="w-4 h-4 transition-transform duration-300 group-hover:translate-x-1" />
                      </div>
                    </div>
                  </div>
                </Link>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Mobile/Tablet Layout - Horizontal Scroll with Side Buttons */}
      {(isMobile || isTablet) && (
        <div className="relative z-10">
          {/* Title Section */}
          <div className="text-center mb-8 px-4">
            {/* Floating Badge - Exact match for mobile */}
            <div
              ref={badgeRef}
              className="inline-flex items-center bg-gradient-to-r from-gray-900 to-gray-700 text-white rounded-full px-5 py-2.5 mb-6 shadow-lg mx-auto w-fit"
            >
              <Zap className="w-4 h-4 mr-2" />
              <span className="text-sm font-manrope font-medium tracking-wide">LATEST INSIGHTS</span>
            </div>

            <h2
              ref={titleRef}
              className="font-marcellus text-4xl md:text-5xl text-gray-900 mb-3 leading-tight"
            >
              Blogs & Insights
            </h2>

            <p
              ref={textRef}
              className="font-instrument text-gray-600 max-w-2xl mx-auto mb-6 leading-relaxed text-base"
            >
              Discover strategies, ideas, and insights from our team
            </p>
          </div>

          {/* Horizontal Scroll Container with Side Buttons */}
          <div className="relative">
            {/* Side Navigation Buttons */}
            <button
              ref={prevButtonRef}
              onClick={() => scrollTo('prev')}
              className="absolute left-2 top-1/2 -translate-y-1/2 z-20 w-10 h-10 bg-white/90 backdrop-blur-sm rounded-full shadow-lg flex items-center justify-center hover:bg-gray-100 transition-all duration-300 border border-gray-200 disabled:opacity-50 disabled:cursor-not-allowed"
              disabled={currentPosition >= 0}
            >
              <ChevronLeft className="w-5 h-5 text-gray-700" />
            </button>

            <button
              ref={nextButtonRef}
              onClick={() => scrollTo('next')}
              className="absolute right-2 top-1/2 -translate-y-1/2 z-20 w-10 h-10 bg-white/90 backdrop-blur-sm rounded-full shadow-lg flex items-center justify-center hover:bg-gray-100 transition-all duration-300 border border-gray-200 disabled:opacity-50 disabled:cursor-not-allowed"
              disabled={currentPosition <= -scrollLength}
            >
              <ChevronRight className="w-5 h-5 text-gray-700" />
            </button>

