// components/HeroSection.jsx
"use client";
import { useState, useEffect, useRef } from "react";
import Image from "next/image";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";

if (typeof window !== "undefined") {
  gsap.registerPlugin(ScrollTrigger);
}

export default function HeroSection({ 
  title = "WHAT WE DO",
  subtitle = "Transforming ideas into exceptional digital experiences",
  imageSrc = "https://images.unsplash.com/photo-1551288049-bebda4e38f71?q=80&w=2070&auto=format&fit=crop",
  overlayColor = "bg-white"
}) {
  const [mounted, setMounted] = useState(false);

  const sectionRef = useRef(null);
  const titleRef = useRef(null);
  const subtitleRef = useRef(null);
  const heroContainerRef = useRef(null);

  const heroImageRefTop = useRef(null);
  const heroImageRefBottom = useRef(null);

  useEffect(() => {
    setMounted(true);

    return () => {
      ScrollTrigger.getAll().forEach((trigger) => trigger.kill());
    };
  }, []);

  useEffect(() => {
    if (!mounted) return;

    const timeoutId = setTimeout(() => {
      if (!sectionRef.current) return;

      const ctx = gsap.context(() => {
        // Header animations
        if (titleRef.current) {
          gsap.fromTo(
            titleRef.current,
            { y: 50, opacity: 0 },
            {
              y: 0,
              opacity: 1,
              duration: 1,
              ease: "power4.out",
              scrollTrigger: {
                trigger: sectionRef.current,
                start: "top 80%",
                once: true,
              },
            }
          );
        }

        if (subtitleRef.current) {
          gsap.fromTo(
            subtitleRef.current,
            { y: 40, opacity: 0 },
            {
              y: 0,
              opacity: 1,
              duration: 0.8,
              delay: 0.2,
              ease: "power3.out",
              scrollTrigger: {
                trigger: sectionRef.current,
                start: "top 80%",
                once: true,
              },
            }
          );
        }

        // Hero overlays animation
        if (
          heroImageRefTop.current &&
          heroImageRefBottom.current &&
          heroContainerRef.current
        ) {
          // Top and bottom overlays fully cover image
          gsap.set(heroImageRefTop.current, { top: 0, height: "100%" });
          gsap.set(heroImageRefBottom.current, { bottom: 0, height: "100%" });

          // Slow reveal: top overlay slides up
          gsap.to(heroImageRefTop.current, {
            top: "-100%", // slides fully up
            ease: "power2.out",
            scrollTrigger: {
              trigger: heroContainerRef.current,
              start: "top bottom",
              end: "bottom top", // longer scroll distance
              scrub: 2,
            },
          });

          // Slow reveal: bottom overlay slides down
          gsap.to(heroImageRefBottom.current, {
            bottom: "-100%", // slides fully down
            ease: "power2.out",
            scrollTrigger: {
              trigger: heroContainerRef.current,
              start: "top bottom",
              end: "bottom top", // longer scroll distance
              scrub: 2,
            },
          });
        }
      }, sectionRef);

      return () => ctx.revert();
    }, 100);

    return () => clearTimeout(timeoutId);
  }, [mounted]);


  if (!mounted) return null;

  return (
    <section
      ref={sectionRef}
      className="w-full py-16 px-6 md:px-20 overflow-hidden"
    >
      {/* Header */}
      <div className="text-center mb-16">
        <div className="relative mb-6 flex justify-center">
          <h1
            ref={titleRef}
            className="font-manrope text-[13vw] md:text-[13vw] lg:text-[13vw] font-black uppercase text-gray-900 leading-[0.85] tracking-tight"
          >
            {title}
          </h1>
        </div>
        <p
          ref={subtitleRef}
          className="font-instrument text-xl text-gray-600 max-w-2xl mx-auto"
        >
          {subtitle}
        </p>
      </div>

        {/* Hero Image */}
        <div
          ref={heroContainerRef}
          className="w-full max-w-7xl h-[85vh]  relative overflow-hidden mx-auto flex justify-center items-center"
        >
        {/* Full image */}
        <Image
          src={imageSrc}
          alt={title}
          fill
          className="object-cover w-full h-full mx-auto"
          priority
        />

  {/* Top overlay */}
          <div
            ref={heroImageRefTop}
            className="absolute left-0 w-full bg-white"
          ></div>


        {/* Bottom overlay */}
          <div
            ref={heroImageRefBottom}
            className="absolute left-0 w-full bg-white"
          ></div>
      </div>
    </section>
  );
}

// components/VideoSection.jsx
"use client";
import { useState, useEffect, useRef } from "react";
import Image from "next/image";
import { Zap, Play, ArrowRight } from "lucide-react";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";

gsap.registerPlugin(ScrollTrigger);

const STATS = [
  { value: 50, suffix: "+", label: "Team Members" },
  { value: 200, suffix: "+", label: "Projects Done" },
  { value: 98, suffix: "%", label: "Happy Clients" },
];

const ImageSection = () => {
  const [isHovered, setIsHovered] = useState(false);
  const [clipPath, setClipPath] = useState("");
  const [dims, setDims] = useState({ w: 0, h: 0 });
  const [displayValues, setDisplayValues] = useState(STATS.map(stat => 0));

  const containerRef = useRef(null);
  const badgeRef = useRef(null);
  const titleRef = useRef(null);
  const subtitleRef = useRef(null);
  const headingRef = useRef(null);
  const labelRef = useRef(null);
  const imageRef = useRef(null);
  const statsContainerRef = useRef(null);
  const statsRef = useRef([]);
  const playButtonRef = useRef(null);

  useEffect(() => {
    const update = () => {
      const w = window.innerWidth * 0.9;
      const h = 510;
      setDims({ w, h });
      setClipPath(
        `path('M 20,60 L 150,60 L 210,0 L ${w - 20},0 A 20,20 0,0,1 ${w},20 L ${w},${h - 20} A 20,20 0,0,1 ${w - 20},${h} L 20,${h} A 20,20 0,0,1 0,${h - 20} L 0,80 A 20,20 0,0,1 20,60 Z')`
      );
    };
    update();
    window.addEventListener("resize", update);
    return () => window.removeEventListener("resize", update);
  }, []);

  useEffect(() => {
    const ctx = gsap.context(() => {

      // Badge
      gsap.fromTo(badgeRef.current,
        { opacity: 0, y: -20, scale: 0.9 },
        {
          opacity: 1, y: 0, scale: 1, duration: 0.7, ease: "back.out(1.7)",
          scrollTrigger: { trigger: badgeRef.current, start: "top 80%" },
        }
      );

      // Titles staggered
      gsap.fromTo([titleRef.current, subtitleRef.current],
        { opacity: 0, y: 40 },
        {
          opacity: 1, y: 0, duration: 0.9, ease: "power3.out", stagger: 0.15,
          scrollTrigger: { trigger: titleRef.current, start: "top 80%" },
        }
      );

      // Paragraph
      gsap.fromTo(headingRef.current,
        { opacity: 0, y: 20 },
        {
          opacity: 1, y: 0, duration: 0.8, ease: "power2.out", delay: 0.3,
          scrollTrigger: { trigger: headingRef.current, start: "top 80%" },
        }
      );

      // Label
      gsap.fromTo(labelRef.current,
        { opacity: 0, x: -20 },
        {
          opacity: 1, x: 0, duration: 0.6, ease: "power2.out",
          scrollTrigger: { trigger: labelRef.current, start: "top 80%" },
        }
      );

      // Image container
      gsap.fromTo(imageRef.current,
        { opacity: 0, y: 50, scale: 0.97 },
        {
          opacity: 1, y: 0, scale: 1, duration: 1, ease: "power3.out",
          scrollTrigger: { trigger: imageRef.current, start: "top 80%" },
        }
      );

      // Stats cards
      gsap.fromTo(statsRef.current,
        { opacity: 0, y: 40, scale: 0.95 },
        {
          opacity: 1, y: 0, scale: 1, duration: 0.7, ease: "power3.out", stagger: 0.1,
          scrollTrigger: { 
            trigger: statsContainerRef.current, 
            start: "top 90%",
            toggleActions: "play none none reverse",
          },
        }
      );

    });

    return () => ctx.revert();
  }, []);

  // Counter animation - start immediately on mount
  useEffect(() => {
    const counters = STATS.map((stat, i) => {
      return gsap.to({ val: 0 }, {
        val: stat.value,
        duration: 2,
        ease: "power2.out",
        delay: i * 0.2,
        onUpdate: function () {
          setDisplayValues(prev => {
            const updated = [...prev];
            updated[i] = Math.round(this.targets()[0].val);
            return updated;
          });
        },
      });
    });

    return () => {
      counters.forEach(counter => counter.kill());
    };
  }, []);

  return (
    <div className="flex flex-col justify-center items-center min-h-screen py-16 px-5 bg-white">
      <div className="relative w-[90vw] max-w-7xl">

        {/* Top Section */}
        <div className="text-center mb-12">

          {/* Badge */}
          <div
            ref={badgeRef}
           className="inline-flex items-center bg-gradient-to-r from-gray-900 to-gray-700 text-white rounded-full px-5 py-2.5 mb-6 shadow-lg"
          >
            <Zap className="w-4 h-4 mr-2 text-gray-100" />
             <span className="text-sm font-manrope font-medium tracking-wide">
              ABOUT RIDEN TECH
            </span>
          </div>

          {/* Titles */}
          <h2
            ref={titleRef}
            className="font-marcellus text-5xl md:text-6xl lg:text-7xl text-gray-900 mb-2"
          >
            We're on a Mission to
          </h2>
          <h2
            ref={subtitleRef}
            className="font-marcellus text-5xl md:text-6xl lg:text-7xl text-gray-900 mb-6"
          >
            Transform <span className="text-gray-400 italic">Digital</span>
          </h2>

          {/* Subheading */}
          <p
            ref={headingRef}
            className="font-instrument text-xl text-gray-600 max-w-2xl mx-auto leading-relaxed"
          >
            We're not just developers we're partners in your success, bringing together
            strategy, design, and technology to create exceptional digital experiences.
          </p>
        </div>

        {/* Label */}
        <div ref={labelRef} className="flex items-center gap-2.5 mb-3.5 pl-0.5 absolute top-1/3 -mt-2 left-3">
          <div className="w-2 h-2 rounded-full bg-gray-400 shrink-0" />
          <span className="text-xs font-manrope tracking-[0.2em] text-gray-500 uppercase">
            Our Workspace
          </span>
        </div>

        {/* Image Container */}
        <div
          ref={(el) => { containerRef.current = el; imageRef.current = el; }}
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
          className="relative overflow-hidden cursor-pointer group"
          style={{
            width: dims.w || "90vw",
            height: dims.h || 510,
            clipPath: clipPath,
            boxShadow: isHovered
              ? "0 25px 50px -12px rgba(0, 0, 0, 0.25)"
              : "0 10px 40px -12px rgba(0, 0, 0, 0.15)",
            transition: "box-shadow 0.4s ease",
          }}
        >
          {/* Image - Web Dev/Office related */}
          <Image
            src="https://images.pexels.com/photos/3183197/pexels-photo-3183197.jpeg?auto=compress&cs=tinysrgb&w=1260&h=750&dpr=2"
            alt="Modern office workspace with developers"
            fill
            className="object-cover transition-transform duration-700 group-hover:scale-110"
            priority
          />
          
          {/* Dark overlay */}
          <div
            className="absolute inset-0 bg-black/30 group-hover:bg-black/20 transition-colors duration-500"
          />
          
          {/* Bottom gradient */}
          <div
            className="absolute bottom-0 left-0 right-0 h-[40%] bg-gradient-to-t from-black/60 to-transparent"
          />

       

          {/* Image caption */}
          <div className="absolute bottom-6 right-6 bg-black/70 backdrop-blur-sm text-white px-4 py-2 rounded-full text-sm font-manrope border border-white/20">
            Modern Development Studio
          </div>
        </div>

        {/* Stats Cards */}
        <div ref={statsContainerRef} className="mt-10 grid grid-cols-1 md:grid-cols-3 gap-6">
          {STATS.map((stat, index) => (
            <div
              key={index}
              ref={el => statsRef.current[index] = el}
              className="bg-white rounded-xl p-8 text-center border border-gray-200 shadow-sm hover:shadow-xl hover:border-gray-400 transition-all duration-300 group"
            >
              <div
                className="font-marcellus text-5xl md:text-6xl text-gray-900 mb-2"
              >
                {displayValues[index]}{stat.suffix}
              </div>
              <div
                className="font-manrope text-sm text-gray-500 uppercase tracking-wider"
              >
                {stat.label}
              </div>
              
              {/* Decorative line on hover */}
              <div className="w-0 h-0.5 bg-black mt-4 mx-auto group-hover:w-16 transition-all duration-500"></div>
            </div>
          ))}
        </div>

        {/* CTA Button */}
        <div className="text-center mt-12">
          <button className="group inline-flex items-center gap-2 bg-gray-900 text-white px-8 py-4 rounded-lg text-sm font-medium hover:bg-gray-800 transition-all duration-300 hover:shadow-xl font-manrope">
            <span>Learn More About Us</span>
            <ArrowRight className="w-4 h-4 transition-transform duration-300 group-hover:translate-x-1" />
          </button>
        </div>

      </div>
    </div>
  );
};

export default ImageSection;

// components/Navbar.jsx
"use client";
import { useState, useEffect, useRef } from "react";
import Link from "next/link";
import { Menu, X, ChevronDown, ArrowRight } from "lucide-react";
import gsap from "gsap";

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [activeDropdown, setActiveDropdown] = useState(null);
  const [mobileExpanded, setMobileExpanded] = useState({});
  const [scrolled, setScrolled] = useState(false);
  const [mounted, setMounted] = useState(false);
  
  // Refs for GSAP animations
  const navbarRef = useRef(null);
  const navLinksRef = useRef([]);
  const ctaButtonRef = useRef(null);
  const mobileMenuRef = useRef(null);
  const dropdownRefs = useRef({});
  const underlineRefs = useRef({});
  const mobileDropdownRefs = useRef({});
  const logoRef = useRef(null);
  const accentLineRef = useRef(null);
  
  // Timeout ref for hover delay
  const hoverTimeoutRef = useRef(null);

  useEffect(() => {
    setMounted(true);
  }, []);

  // Run animations after mounted
  useEffect(() => {
    if (!mounted) return;
    
    const ctx = gsap.context(() => {
      const tl = gsap.timeline();
      
      // Navbar slide down
      tl.fromTo(navbarRef.current, 
        { y: -100, opacity: 0 },
        { y: 0, opacity: 1, duration: 1.2, ease: "power4.out" }
      );
      
      // Accent line animation
      tl.fromTo(accentLineRef.current,
        { scaleX: 0, transformOrigin: "left" },
        { scaleX: 1, duration: 1.5, ease: "power4.out" },
        "-=0.8"
      );
      
      // Logo fade in
      if (logoRef.current) {
        tl.fromTo(logoRef.current,
          { opacity: 0 },
          { opacity: 1, duration: 0.8, ease: "power2.out" },
          "-=0.6"
        );
      }
      
      // Nav links fade in one by one
      const validNavLinks = navLinksRef.current.filter(el => el);
      if (validNavLinks.length > 0) {
        tl.fromTo(validNavLinks,
          { opacity: 0 },
          { 
            opacity: 1, 
            duration: 0.6, 
            stagger: 0.1, 
            ease: "power2.out"
          },
          "-=0.4"
        );
      }
      
      // CTA button fade in
      if (ctaButtonRef.current) {
        tl.fromTo(ctaButtonRef.current,
          { opacity: 0 },
          { opacity: 1, duration: 0.6, ease: "power2.out" },
          "-=0.2"
        );
      }
    });

    return () => ctx.revert();
  }, [mounted]);

  // Handle scroll effect
  useEffect(() => {
    const handleScroll = () => {
      const isScrolled = window.scrollY > 20;
      if (isScrolled !== scrolled) {
        setScrolled(isScrolled);
        gsap.to(navbarRef.current, {
          backgroundColor: isScrolled ? "rgba(255, 255, 255, 0.95)" : "rgba(255, 255, 255, 1)",
          backdropFilter: isScrolled ? "blur(8px)" : "blur(0px)",
          duration: 0.6,
          ease: "power3.inOut"
        });
      }
    };
    
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, [scrolled]);

  // Animate mobile menu
  useEffect(() => {
    if (isOpen && mobileMenuRef.current) {
      gsap.fromTo(mobileMenuRef.current,
        { y: -30, opacity: 0 },
        { y: 0, opacity: 1, duration: 0.6, ease: "power4.out" }
      );
      
      gsap.fromTo(
        mobileMenuRef.current.children,
        { x: -30, opacity: 0 },
        { x: 0, opacity: 1, duration: 0.5, stagger: 0.08, ease: "power3.out" }
      );
    }
  }, [isOpen]);

  // Animate desktop dropdown
  useEffect(() => {
    if (window.innerWidth >= 1024 && activeDropdown && dropdownRefs.current[activeDropdown]) {
      const dropdown = dropdownRefs.current[activeDropdown];
      
      gsap.fromTo(dropdown,
        { y: -15, opacity: 0 },
        { y: 0, opacity: 1, duration: 0.5, ease: "power3.out" }
      );
      
      gsap.fromTo(
        dropdown.querySelectorAll('.dropdown-item'),
        { y: -8, opacity: 0 },
        { y: 0, opacity: 1, duration: 0.4, stagger: 0.03, delay: 0.1, ease: "power2.out" }
      );
    }
  }, [activeDropdown]);

  // Animate mobile dropdown expand/collapse
  useEffect(() => {
    Object.keys(mobileExpanded).forEach((key) => {
      const element = mobileDropdownRefs.current[key];
      if (element) {
        if (mobileExpanded[key]) {
          element.style.height = 'auto';
          const height = element.scrollHeight;
          element.style.height = '0px';
          element.offsetHeight;
          
          gsap.to(element, {
            height: height,
            opacity: 1,
            duration: 0.5,
            ease: "power3.inOut",
            onComplete: () => {
              element.style.height = 'auto';
            }
          });
        } else {
          const height = element.scrollHeight;
          element.style.height = height + 'px';
          element.offsetHeight;
          
          gsap.to(element, {
            height: 0,
            opacity: 0,
            duration: 0.4,
            ease: "power3.in"
          });
        }
      }
    });
  }, [mobileExpanded]);

  // Animate underline on hover
  const handleUnderlineHover = (key, isHovering) => {
    if (underlineRefs.current[key]) {
      gsap.to(underlineRefs.current[key], {
        scaleX: isHovering ? 1 : 0,
        duration: 0.5,
        ease: "power3.out"
      });
    }
  };

  // Clear any existing hover timeout
  const clearHoverTimeout = () => {
    if (hoverTimeoutRef.current) {
      clearTimeout(hoverTimeoutRef.current);
      hoverTimeoutRef.current = null;
    }
  };

  // Handle mouse enter on nav item
  const handleNavItemEnter = (title) => {
    clearHoverTimeout();
    if (window.innerWidth >= 1024) {
      if (activeDropdown !== title) {
        if (activeDropdown) {
          handleUnderlineHover(`${activeDropdown}-desktop`, false);
        }
        setActiveDropdown(title);
        handleUnderlineHover(`${title}-desktop`, true);
      }
    }
  };

  // Handle mouse leave from nav item
  const handleNavItemLeave = () => {
    clearHoverTimeout();
    hoverTimeoutRef.current = setTimeout(() => {
      if (window.innerWidth >= 1024 && activeDropdown) {
        const dropdown = dropdownRefs.current[activeDropdown];
        if (!dropdown || !dropdown.matches(':hover')) {
          handleUnderlineHover(`${activeDropdown}-desktop`, false);
          setActiveDropdown(null);
        }
      }
      hoverTimeoutRef.current = null;
    }, 100);
  };

  // Handle mouse enter on dropdown
  const handleDropdownEnter = (title) => {
    clearHoverTimeout();
    if (window.innerWidth >= 1024) {
      if (activeDropdown !== title) {
        if (activeDropdown) {
          handleUnderlineHover(`${activeDropdown}-desktop`, false);
        }
        setActiveDropdown(title);
        handleUnderlineHover(`${title}-desktop`, true);
      }
    }
  };

  // Handle mouse leave from dropdown
  const handleDropdownLeave = (title) => {
    clearHoverTimeout();
    hoverTimeoutRef.current = setTimeout(() => {
      if (window.innerWidth >= 1024 && activeDropdown === title) {
        const navItem = document.querySelector(`[data-navitem="${title}"]`);
        if (!navItem || !navItem.matches(':hover')) {
          handleUnderlineHover(`${title}-desktop`, false);
          setActiveDropdown(null);
        }
      }
      hoverTimeoutRef.current = null;
    }, 100);
  };

  // Handle click on nav item with dropdown
  const handleNavItemClick = (e, item) => {
    if (item.href) {
      // Navigate to the main page
      window.location.href = item.href;
    }
  };

  // Handle click on dropdown link
  const handleDropdownLinkClick = () => {
    handleUnderlineHover(`${activeDropdown}-desktop`, false);
