            <span className="text-sm font-manrope tracking-wide">TECHNOLOGIES</span>
          </div>

          {/* Title */}
          <h2
            ref={titleRef}
            className="font-marcellus text-4xl md:text-5xl lg:text-6xl text-gray-900 mb-4"
